(90,43,3,'Nokia E71-style clone','QWERTY “corporate” style phone (non-genuine Nokia).','Inspired by Nokia E71; knock-offs had weaker build and limited software.','Resistive screen, claimed 12 MP camera unlikely accurate; generic OS.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(91,44,3,'BLU Jenny TV 2.8 T276T','BLU Jenny 2.8 basic phone with analog TV.','2015-era BLU feature phone for Latin America; TV and dual SIM.','2.8" QVGA, dual SIM, FM, VGA camera, 1450 mAh.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(92,45,3,'Nokia C3-00','Nokia C3-00 QWERTY Wi-Fi feature phone.','April 2010; Wi-Fi and social apps; popular with students in Brazil.','2.4" TFT, Series 40, no 3G, 2 MP camera, 1320 mAh.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(93,46,3,'Nokia X1-01','Nokia X1-01 dual-SIM music phone.','June 2011 Series 30; long battery life and loud speaker.','1.8" 128×160, dual SIM, no camera, 1320 mAh.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(94,47,3,'Samsung GT-C3312','Samsung Champ Deluxe Duos touch dual-SIM.','2012 resistive touch, TouchWiz Lite, no Wi-Fi.','2.8" QVGA, 1.3 MP, Bluetooth 3.0, microSD 16 GB.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(95,48,3,'Samsung C3510 Genoa','Samsung C3510 Genoa touch feature phone.','Late 2009 social-focused touchscreen before Galaxy dominance.','2.8" resistive, 1.3 MP, Bluetooth 2.1.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(96,49,3,'Positivo Selfie','Positivo Selfie budget selfie phone.','2015 Brazil-market phone emphasizing front camera.','4.5" IPS, quad-core, 8 MP front / 5 MP rear, Android 5.0.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(97,50,3,'Foston FS-66','Foston FS-66 MP3/MP4 player.','Mid-2000s compact player; forums swapped firmware.','1.5" color display, 1 GB, FM, voice record, MP3/WMA/AVI.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(98,51,3,'Philips GoGear SA3VBE04K','Philips GoGear SA3VBE 4 GB digital audio player.','Early 2010s Walkman-class player with Songbird and FullSound.','1.5" TFT, MP3/WMA/WAV/FLAC, USB, ~20 h playback.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(99,52,3,'Mondial RP-03 radio','Mondial RP-03 portable multiband radio.','AM/FM/SW portable with clock and alarm.','AA or 3 V DC, headphone jack, ~1 W.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(100,53,3,'Philco PH60 radio','Philco PH60 World Receiver (2010).','Portable multiband receiver for AM/FM/SW.','10 bands, digital tuning, telescopic antenna.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(101,54,3,'Casio SF-5500B organizer','Casio SF-5500B 128 KB business organizer.','1995 Thailand; contacts, calendar, memo, expense tracker.','128 KB, 16×4 LCD, CR2032 batteries.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(102,55,3,'Toshiba Satellite 2455-S305','Toshiba Satellite 2455-S305 desktop-replacement notebook.','2002 Pentium 4 multimedia laptop with Harman/Kardon audio.','P4 2.4 GHz, 512 MB RAM, 60 GB HDD, 15" XGA, GeForce4 420 Go, DVD-R/RW, Win XP.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(103,56,3,'Toshiba Satellite Pro T2150CDS/520','Toshiba Satellite Pro T2150CDS/520 (1995).','486DX4 laptop with built-in 2× CD-ROM for early multimedia.','75 MHz 486DX4, 500 MB HDD, 10.4" DSTN, DOS/Windows 3.11.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(104,57,3,'Toshiba Satellite 2065CDS/4.3','Toshiba Satellite 2065CDS/4.3 with AMD K6-2.','~1999 entry Satellite with 366 MHz K6-2 and 4.3 GB disk.','32 MB RAM, 24× CD-ROM, 12.1" dual-scan, Win 98.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(105,58,3,'MOXPAD 840 4G tablet','Generic MOXPAD 840 4G tablet (China).','Budget P.R.C. tablet with accessories; limited documentation.','~8–10" touchscreen, DC 9 V, microSD, basic Android-era hardware.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(106,59,3,'Elsys 4100 satellite receiver','Elsys 4100 analog C-band satellite TV receiver.','Popular in rural Brazil for free-to-air analog satellite before digital migration.','Banda C, H/V switching, channel memory, RCA outputs.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(107,60,3,'Gradiente speaker','Gradiente passive satellite speaker from a 5.1 set.','2000s Brazil home-theater satellite; Gradiente audio heritage.','~30–60 W, 4–8 Ω, full-range driver, bass reflex ports.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(108,61,3,'Puma digital LED watch','Puma digital LED watch.','2000s sporty LED/LCD fashion watches.','Backlight, alarm/timer, 3 ATM, rubber strap.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(109,62,3,'Sierra Wireless USB modem (AT&T)','Sierra Wireless AT&T USB Connect Lightning modem.','3G/4G LTE USB dongle for laptops (FCC N7NU305).','LTE/3G bands for North America; plug-and-play Windows/Mac.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(110,63,3,'Xwear XS9 Ultra 2 Max smartwatch','Xwear XS9 Ultra 2 Max smartwatch.','Brazilian-value wearable with health sensors and sports modes.','2.2" IPS, Bluetooth 5.2, 220 mAh, heart rate and SpO2 style sensors (wellness).','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(111,64,3,'Genius MaxFire G-12U gamepad','Genius MaxFire G-12U USB gamepad with vibration.','2000s PC gamepad with dual analog and racing mode.','10 buttons, dual sticks, vibration, USB, Windows 98–Vista.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(112,65,3,'Aquarius Discovery GPS MTC-3842','Aquarius Discovery Channel licensed GPS navigator.','2013–2014 Brazil portable navigator with TV and reverse camera input.','4.3" WinCE 6, iGO-style maps, digital TV, reverse camera.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
(113,66,3,'Elecom TK-U89MPSV keyboard','Elecom TK-U89MPSV 89-key Japanese USB keyboard.','Early 2000s compact scissor (pantograph) JIS keyboard.','89 keys, 1.5 m cable, silver, Windows 98–XP.','2026-03-29 12:00:00','2026-03-29 12:00:00'),
